        {tab === "consilium" && (company.overview ? renderConsilium() : renderComingSoon("╨Ъ╨╛╨╜╤Б╨╕╨╗╨╕╤Г╨╝ ╨░╨╜╨░╨╗╨╕╤В╨╕╨║╨╛╨▓"))}
